import { GoogleGenAI } from "@google/genai";
import { Message } from "../types";

const SYSTEM_INSTRUCTION = `
Sei l'assistente virtuale esperto di Nardin Autotrasporti. 
La tua missione è aiutare i potenziali clienti con consulenza logistica sui trasporti speciali e sollevamenti con gru.

Dati aziendali:
- Nome: Nardin Autotrasporti
- Specializzazioni: Trasporti eccezionali, sollevamento industriale, movimentazione barche, noleggio autogrù con operatore.
- Sede: Via Linz 1, 38121 Trento (TN).
- Area Operativa: Forti radici in Trentino-Alto Adige (Trento, Bolzano, Rovereto, Riva del Garda), ma operano a livello nazionale ed internazionale.

Regole:
1. Per domande su posizioni geografiche o itinerari, usa i dati di Google Maps se disponibili.
2. Se chiedono preventivi, spiega quali dati servono (dimensioni, peso, punto di carico/scarico).
3. Fornisci consigli tecnici su come preparare un carico speciale (es. permessi, scorte).
4. Se non sai qualcosa, invita a contattare l'ufficio tecnico al numero +39 041 123 4567.
5. Rispondi sempre in italiano in modo tecnico ma cordiale.
`;

export async function chatWithConsultant(messages: Message[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents = messages.map(m => ({
    role: m.role,
    parts: [{ text: m.text }]
  }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.5,
        tools: [{ googleMaps: {} }],
      },
    });

    return {
      text: response.text || "Mi dispiace, si è verificato un errore.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    return {
      text: "Servizio temporaneamente non disponibile. Contattaci direttamente.",
      grounding: undefined
    };
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { chatWithConsultant } from '../services/geminiService';
import { Message } from '../types';

const AIConsultant: React.FC = () => {
  const [messages, setMessages] = useState<(Message & { grounding?: any[] })[]>([
    { role: 'model', text: 'Benvenuto in Nardin Autotrasporti! Sono il tuo consulente virtuale. Posso aiutarti a pianificare un trasporto speciale o darti indicazioni sulla nostra sede a Trento?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage = { role: 'user' as const, text: input };
    const newMessages = [...messages, userMessage];
    setMessages(newMessages);
    setInput('');
    setIsTyping(true);

    const result = await chatWithConsultant(newMessages);

    setMessages([...newMessages, { role: 'model', text: result.text, grounding: result.grounding }]);
    setIsTyping(false);
  };

  return (
    <div className="flex flex-col h-full bg-gray-50 overflow-hidden">
      <div 
        ref={scrollRef}
        className="flex-grow p-4 overflow-y-auto space-y-4 scroll-smooth"
      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}
          >
            <div 
              className={`max-w-[90%] p-3 px-4 rounded-2xl text-[13px] leading-relaxed shadow-sm animate-in fade-in slide-in-from-bottom-2 duration-300 ${
                msg.role === 'user' 
                  ? 'bg-orange-600 text-white rounded-tr-none' 
                  : 'bg-white text-gray-800 border border-gray-200 rounded-tl-none'
              }`}
            >
              {msg.text}

              {msg.grounding && msg.grounding.length > 0 && (
                <div className="mt-3 pt-2 border-t border-gray-100 flex flex-col gap-2">
                  <p className="text-[9px] uppercase font-black text-gray-400">Riferimenti Mappe:</p>
                  {msg.grounding.map((chunk, cIdx) => (
                    chunk.maps && (
                      <a 
                        key={cIdx} 
                        href={chunk.maps.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 p-2 bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100 transition-colors no-underline"
                      >
                        <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/></svg>
                        <span className="text-[10px] font-bold truncate">{chunk.maps.title || 'Vedi su Google Maps'}</span>
                      </a>
                    )
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-in fade-in duration-300">
            <div className="bg-white border border-gray-200 p-3 px-4 rounded-2xl rounded-tl-none flex space-x-1.5 items-center">
              <div className="w-1.5 h-1.5 bg-orange-600 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-orange-600 rounded-full animate-bounce delay-150"></div>
              <div className="w-1.5 h-1.5 bg-orange-600 rounded-full animate-bounce delay-300"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-gray-100 flex-shrink-0">
        <form onSubmit={handleSend} className="flex space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Chiedi posizione o consigli tecnici..."
            className="flex-grow bg-gray-100 border-none rounded-full px-5 py-3 text-sm focus:ring-2 focus:ring-orange-500 transition-all outline-none"
          />
          <button
            type="submit"
            disabled={!input.trim() || isTyping}
            className="bg-orange-600 text-white p-3 rounded-full hover:bg-orange-700 disabled:opacity-50 transition-all shadow-lg flex-shrink-0"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </form>
      </div>
    </div>
  );
};

