3. Non rispondere "Contatta l'ufficio" se la domanda riguarda una posizione o un tragitto che puoi trovare sulle mappe. Rispondi con i dati delle mappe e poi offri assistenza umana per i dettagli tecnici del carico.
4. Rispondi sempre in italiano, con tono professionale e preciso.
`;

export async function chatWithConsultant(messages: Message[]) {
  // Inizializzazione diretta con process.env.API_KEY come da linee guida
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents = messages.map(m => ({
    role: m.role,
    parts: [{ text: m.text }]
  }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.3, // Abbassata per maggiore precisione sui dati
        tools: [{ googleMaps: {} }],
      },
    });

    return {
      text: response.text || "Mi dispiace, non sono riuscito a generare una risposta. Riprova.",
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    return {
      text: "Servizio di consulenza temporaneamente non disponibile. Chiamaci al +39 041 123 4567.",
      grounding: undefined
    };
  }
}

