}

import React, { useState, useRef, useEffect } from 'react';
import { chatWithConsultant } from '../services/geminiService';
import { Message } from '../types';

const AIConsultant: React.FC = () => {
  const [messages, setMessages] = useState<(Message & { grounding?: any[] })[]>([
    { role: 'model', text: 'Benvenuto in Nardin Autotrasporti! Sono il tuo consulente logistico.\n\nPosso aiutarti a calcolare un percorso per un trasporto speciale, dirti quanto distiamo da un cantiere o mostrarti i dettagli della nostra sede a Trento. Come posso esserti utile?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage = { role: 'user' as const, text: input };
    const newMessages = [...messages, userMessage];
    setMessages(newMessages);
    setInput('');
    setIsTyping(true);

    const result = await chatWithConsultant(newMessages);

    setMessages([...newMessages, { role: 'model', text: result.text, grounding: result.grounding }]);
    setIsTyping(false);
  };

  return (
    <div className="flex flex-col h-full bg-gray-50 overflow-hidden">
      <div 
        ref={scrollRef}
        className="flex-grow p-4 overflow-y-auto space-y-4 scroll-smooth"
      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}
          >
            <div 
              className={`max-w-[90%] p-3 px-4 rounded-2xl text-[13px] leading-relaxed shadow-sm animate-in fade-in slide-in-from-bottom-2 duration-300 whitespace-pre-wrap ${
                msg.role === 'user' 
                  ? 'bg-orange-600 text-white rounded-tr-none font-medium' 
                  : 'bg-white text-gray-800 border border-gray-200 rounded-tl-none'
              }`}
            >
              {msg.text}

              {msg.grounding && msg.grounding.length > 0 && (
                <div className="mt-4 pt-3 border-t border-gray-100 flex flex-col gap-2">
                  <p className="text-[9px] uppercase font-black text-orange-600 tracking-tighter">Fonti e Mappe verificate:</p>
                  <div className="grid grid-cols-1 gap-2">
                    {msg.grounding.map((chunk, cIdx) => (
                      <React.Fragment key={cIdx}>
                        {chunk.maps && (
                          <a 
                            href={chunk.maps.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="flex items-center gap-2 p-2 bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100 transition-colors no-underline border border-blue-100"
                          >
                            <svg className="w-3.5 h-3.5 flex-shrink-0" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/></svg>
                            <span className="text-[10px] font-bold truncate">{chunk.maps.title || 'Vedi posizione su Google Maps'}</span>
                          </a>
                        )}
                        {chunk.web && (
                          <a 
                            href={chunk.web.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="flex items-center gap-2 p-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors no-underline border border-gray-200"
                          >
                            <svg className="w-3.5 h-3.5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/></svg>
                            <span className="text-[10px] font-bold truncate">{chunk.web.title || 'Dettagli tecnici esterni'}</span>
                          </a>
                        )}
                      </React.Fragment>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-in fade-in duration-300">
            <div className="bg-white border border-gray-200 p-3 px-4 rounded-2xl rounded-tl-none flex space-x-1.5 items-center">
              <div className="w-1.5 h-1.5 bg-orange-600 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-orange-600 rounded-full animate-bounce delay-150"></div>
              <div className="w-1.5 h-1.5 bg-orange-600 rounded-full animate-bounce delay-300"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-gray-100 flex-shrink-0">
        <form onSubmit={handleSend} className="flex space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Chiedi un percorso o una distanza..."
            className="flex-grow bg-gray-100 border-none rounded-full px-5 py-3 text-sm focus:ring-2 focus:ring-orange-500 transition-all outline-none"
          />
          <button
            type="submit"
            disabled={!input.trim() || isTyping}
            className="bg-orange-600 text-white p-3 rounded-full hover:bg-orange-700 disabled:opacity-50 transition-all shadow-lg flex-shrink-0"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </form>
      </div>
    </div>
  );
};

