document.addEventListener('DOMContentLoaded', () => {

    // 1. Navbar Sticky & Scroll Class
    const navbar = document.getElementById('navbar');
    window.addEventListener('scroll', () => {
        if (window.scrollY > 50) {
            navbar.classList.add('scrolled');
        } else {
            navbar.classList.remove('scrolled');
        }
    });

    // 2. Menu Mobile Toggle
    const menuToggle = document.getElementById('menu-toggle');
    const navLinks = document.getElementById('nav-links');

    menuToggle.addEventListener('click', () => {
        navLinks.classList.toggle('active');
    });

    // Chiudi menu quando si clicca un link
    document.querySelectorAll('.nav-links a').forEach(link => {
        link.addEventListener('click', () => {
            navLinks.classList.remove('active');
        });
    });

    // 3. Filtro Flotta
    const filterBtns = document.querySelectorAll('.filter-btn');
    const fleetCards = document.querySelectorAll('.fleet-card');

    filterBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            // Rimuovi classe active da tutti
            filterBtns.forEach(b => b.classList.remove('active'));
            // Aggiungi active al cliccato
            btn.classList.add('active');

            const filter = btn.getAttribute('data-filter');

            fleetCards.forEach(card => {
                const cardCat = card.getAttribute('data-cat');
                if (filter === 'all' || filter === cardCat) {
                    card.style.display = 'block';
                    // Animazione comparsa
                    card.animate([
                        { opacity: 0, transform: 'scale(0.95)' },
                        { opacity: 1, transform: 'scale(1)' }
                    ], { duration: 400, easing: 'ease-out' });
                } else {
                    card.style.display = 'none';
                }
            });
        });
    });

    // 4. Smooth Scroll aggiuntivo per i pulsanti Hero
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function (e) {
            e.preventDefault();
            const target = document.querySelector(this.getAttribute('href'));
            if (target) {
                window.scrollTo({
                    top: target.offsetTop - 80, // Offset per la navbar sticky
                    behavior: 'smooth'
                });
            }
        });
    });
});

