function renderFleet(filter = 'Tutti') {
    const grid = document.getElementById('fleet-grid');
    grid.innerHTML = '';

    const items = filter === 'Tutti' ? fleetData : fleetData.filter(i => i.cat === filter);

    items.forEach(item => {
        grid.innerHTML += `
            <div class="group bg-white rounded-[1.2rem] overflow-hidden border border-gray-100 shadow-sm hover:shadow-xl transition-all duration-500 animate-in">
